<div class="d-flex justify-content-between align-items-center mb-4"><div><h2 class="h3 fw-bold mb-1">Responsables de <?= e($estudiante['nombres']) ?></h2><p class="text-muted mb-0">Asocia varios responsables al estudiante.</p></div><a href="<?= e(url('/estudiantes')) ?>" class="btn btn-outline-secondary">Volver</a></div>
<?php if (!empty($success)): ?><div class="alert alert-success"><?= e($success) ?></div><?php endif; ?>
<?php if (!empty($errors)): ?><div class="alert alert-danger"><ul class="mb-0"><?php foreach($errors as $error): ?><li><?= e($error) ?></li><?php endforeach; ?></ul></div><?php endif; ?>
<div class="row g-4"><div class="col-lg-5"><form method="post" action="<?= e(url('/estudiantes/responsables?id='.$estudiante['id_estudiante'])) ?>" class="panel-card"><?= csrf_field() ?><h3 class="h5 fw-bold">Agregar responsable</h3><div class="mb-3"><label class="form-label">Responsable</label><select name="id_responsable" class="form-select" required><option value="">Seleccionar</option><?php foreach($responsables as $r): ?><option value="<?= e((string)$r['id_responsable']) ?>"><?= e($r['apellido_paterno'].' '.$r['apellido_materno'].' '.$r['nombres']) ?></option><?php endforeach; ?></select></div><div class="mb-3"><label class="form-label">Parentesco</label><select name="parentesco" class="form-select"><option value="">Seleccionar</option><?php foreach(['Padre','Madre','Tutor','Otro'] as $p): ?><option value="<?= e($p) ?>"><?= e($p) ?></option><?php endforeach; ?></select></div><div class="form-check"><input class="form-check-input" type="checkbox" name="es_principal" id="principal"><label class="form-check-label" for="principal">Responsable principal</label></div><div class="form-check"><input class="form-check-input" type="checkbox" name="vive_con_estudiante" id="vive"><label class="form-check-label" for="vive">Vive con el estudiante</label></div><div class="form-check mb-3"><input class="form-check-input" type="checkbox" name="autorizado_recoger" id="recoge"><label class="form-check-label" for="recoge">Autorizado para recoger</label></div><button class="btn btn-primary">Asociar</button></form></div><div class="col-lg-7"><div class="panel-card p-0 overflow-hidden"><table class="table mb-0 align-middle"><thead class="table-light"><tr><th>Responsable</th><th>Parentesco</th><th>Flags</th><th></th></tr></thead><tbody><?php if(empty($relaciones)): ?><tr><td colspan="4" class="text-center text-muted py-4">Sin responsables asociados.</td></tr><?php endif; ?><?php foreach($relaciones as $rel): ?><tr><td><strong><?= e($rel['apellido_paterno'].' '.$rel['apellido_materno'].' '.$rel['nombres']) ?></strong><div class="small text-muted"><?= e($rel['celular'] ?? '') ?></div></td><td><?= e($rel['parentesco'] ?? '-') ?></td><td><?= (int)$rel['es_principal']===1 ? '<span class="badge text-bg-primary">Principal</span> ' : '' ?><?= (int)$rel['vive_con_estudiante']===1 ? '<span class="badge text-bg-info">Vive</span> ' : '' ?><?= (int)$rel['autorizado_recoger']===1 ? '<span class="badge text-bg-success">Recoge</span>' : '' ?></td><td class="text-end"><form method="post" action="<?= e(url('/estudiantes/responsables/eliminar?id='.$estudiante['id_estudiante'])) ?>"><?= csrf_field() ?><input type="hidden" name="relacion_id" value="<?= e((string)$rel['id_estudiante_responsable']) ?>"><button class="btn btn-outline-danger btn-sm">Quitar</button></form></td></tr><?php endforeach; ?></tbody></table></div></div></div>
